{
    "messages": [
        {
            "role": "developer",
            "content": "You are Bucky, a friendly assistant for BadgerChat Mini."
        },
        {
            "role": "assistant",
            "content": "Welcome to BadgerChat Mini! Ask me anything."
        },
        {
            "role": "user",
            "content": "hey how are you"
        }
    ]
}

{
    "messages": [
        {
            "role": "developer",
            "content": "Extract the user's personal info."
        },
        {
            "role": "user",
            "content": "Hi, my name is George Washington and I was born in 1732."
        }
    ],
    "response_schema": {
        "type": "object",
        "properties": {
            "name": {
                "type": "string",
                "description": "The person's full name."
            },
            "yearBorn": {
                "type": "integer",
                "description": "The year they were born."
            }
        }
    }
}

{
    "messages": [
        {
            "role": "developer",
            "content": "Extract the user's intent from the message below."
        },
        {
            "role": "user",
            "content": "hey bucky what's the latest comments on badgerchat mini"
        }
    ],
    "response_schema": {
        "type": "object",
        "properties": {
            "action": {
                "type": "string",
                "enum": [
                    "GET_COMMENTS",
                    "LOGIN",
                    "LOGOUT",
                    "CREATE_COMMENT",
                    "UNKNOWN"
                ],
                "description": "Which action the model should request."
            }
        }
    }
}

{
    "messages": [
        {
            "role": "developer",
            "content": "You are Bucky. Use the provided tools when appropriate."
        },
        {
            "role": "user",
            "content": "Show me the five most recent comments."
        }
    ],
    "tools": [
        {
            "type": "function",
            "name": "get_comments",
            "description": "Gets the latest comments on BadgerChat Mini.",
            "parameters": {
                "type": "object",
                "properties": {
                    "n": {
                        "anyOf": [
                            { "type": "integer" },
                            { "type": "null" }
                        ],
                        "description": "Optional max number of comments to return."
                    }
                }
            }
        },
        {
            "type": "function",
            "name": "create_comment",
            "description": "Posts a new comment. The user must be logged in.",
            "parameters": {
                "type": "object",
                "properties": {
                    "comment": {
                        "type": "string"
                    }
                }
            }
        }
    ],
    "tool_choice": "auto"
}

{
    "messages": [
        {
            "role": "developer",
            "content": "You are Bucky. Use the provided tools when appropriate."
        },
        {
            "role": "user",
            "content": "Show me the most recent comment."
        },
        {
            "type": "function_call",
            "call_id": "call_abc123",
            "name": "get_comments",
            "arguments": { "n": 1 }
        },
        {
            "type": "function_call_output",
            "call_id": "call_abc123",
            "output": "{\"comments\":[{\"id\":2,\"author\":\"bucky\",\"comment\":\"hello world\",\"created\":\"2026-04-19T21:06:15.000Z\"}]}"
        }
    ],
    "tools": [
        {
